/bin/bash -lc "node - <<'NODE'
const fs=require('fs');
const lines=fs.readFileSync('data/sales.csv','utf8').trim().split(/\\r?\\n/);
const rows=lines.slice(1).map(x=>{const [order_id,date,region,product,units,unit_price]=x.split(','); return {order_id,date,region,product,units:+units,unit_price:+unit_price,revenue:+units*+unit_price}});
const sum=a=>a.reduce((x,y)=>x+y,0);
const total=sum(rows.map(r=>r.revenue));
const vals=rows.map(r=>r.revenue).sort((a,b)=>a-b);
for (const field of ['product','region']) { const o={}; for(const r of rows)o[r[field]]=(o[r[field]]||0)+r.revenue; console.log(field,o); }
console.log({orders:rows.length,total,median:(vals[14]+vals[15])/2, middle:[vals[14],vals[15]], vals});
NODE"

