/bin/bash -lc "node - <<'NODE'
const fs=require('fs');
const report=fs.readFileSync('REPORT.md','utf8');
const summary=JSON.parse(fs.readFileSync('summary.json','utf8'));
const csv=fs.readFileSync('data/sales.csv','utf8').trim().split(/\\r?\\n/).slice(1).map(x=>x.split(','));
const rev=csv.map(r=>Number(r[4])*Number(r[5]));
const total=rev.reduce((a,b)=>a+b,0);
const sorted=[...rev].sort((a,b)=>a-b);
const byRegion={}; const byProduct={};
for(let i=0;i<csv.length;i++){byRegion[csv[i][2]]=(byRegion[csv[i][2]]||0)+rev[i];byProduct[csv[i][3]]=(byProduct[csv[i][3]]||0)+rev[i];}
const expected={total_revenue:+total.toFixed(2),orders:csv.length,median_order_value:+((sorted[14]+sorted[15])/2).toFixed(2),top_product_by_revenue:Object.entries(byProduct).sort((a,b)=>b[1]-a[1])[0][0],revenue_by_region:Object.fromEntries(Object.entries(byRegion).map(([k,v])=>[k,+v.toFixed(2)]))};
const headings=report.match(/"'^#+ .+$/gm)||[];
const bullets=report.match(/''^- .+$/gm)||[];
const forbidden=/'"\\b(leverage|delve|robust|seamless|revolutionize)\\b/i.test(report);
console.log(JSON.stringify({summaryMatches:JSON.stringify(summary)===JSON.stringify(expected),keys:Object.keys(summary),headings,words:report.trim().split(/\\s+/).length,bulletCount:bullets.length,bulletWords:bullets.map(x=>x.split(/\\s+/).length),forbidden},null,2));
NODE
nl -ba REPORT.md
nl -ba summary.json
git status --short"

